prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?created WHERE {
  ?message a bboExt:Message ;
           bbo:name ?msgName .
  FILTER(CONTAINS(LCASE(STR(?msgName)), LCASE("Auktionshaus")))

  ?message tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?created WHERE {
  {
    ?msg a bboExt:Message .
    ?msg ?labelProp ?labelVal .
    FILTER(
      ( ?labelProp IN (bbo:name, rdfs:label) )
      && CONTAINS(LCASE(STR(?labelVal)), LCASE("Auktionshaus"))
    )
  }
  UNION
  {
    ?flow a bboExt:MessageFlow .
    ?flow bboExt:messageRef ?msgRef .
    FILTER(CONTAINS(LCASE(STR(?msgRef)), LCASE("Auktionshaus")))
  }

  # Join to models through containment
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?created ?elem ?elemName WHERE {
  ?elem tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:modelCreated ?created . }

  {
    ?elem bbo:name ?n .
    FILTER(CONTAINS(LCASE(STR(?n)), LCASE("Auktionshaus")))
  }
  UNION
  {
    ?elem rdfs:label ?n2 .
    FILTER(CONTAINS(LCASE(STR(?n2)), LCASE("Auktionshaus")))
  }
  UNION
  {
    ?elem ?p ?o .
    FILTER(?p IN (bbo:name, rdfs:label))
    FILTER(CONTAINS(LCASE(STR(?o)), LCASE("Auktionshaus")))
  }

  BIND( COALESCE(?n, ?n2, "") AS ?elemName )
}
ORDER BY DESC(?created)
LIMIT 25
